SELECT
    d.*
FROM TB_ORDER_DELIVERY_PARCEL d
JOIN TB_ORDER o ON o.ORDER_ID = d.ORDER_ID
WHERE d.ORDER_ID = #{orderId}

    AND d.OP_TYPE = #{opType}

SELECT
    d.*
FROM tb_order_delivery_freight d
JOIN tb_order o ON o.order_id = d.order_id
WHERE d.order_id = #{orderId}

    AND d.op_type = #{opType}

SELECT
    d.*
FROM tb_order_delivery_factory d
